def get_user(user_id):
    key = f'user:{user_id}'
    cached = r.get(key)
    if cached:
        return json.loads(cached)
    user = db.fetch_user(user_id)  # slow
    r.set(key, json.dumps(user), ex=300)  # 5min TTL
    return user

def is_rate_limited(ip: str, limit=100, window=60) -> bool:
    key = f'rl:{ip}'
    count = r.incr(key)
    if count == 1:
        r.expire(key, window)  # set TTL on first hit
    return count > limit

@app.get('/cache/{key}')
async def get_cache(key: str):
    value = await r.get(key)
    return {'value': value}
